{"path": "/tmp/sv-b35fcb983df24322934de92834708084/RecipeShare/Services/RecipeService.cs", "file_text": "using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly Dictionary<(int recipeId, string visitorId), int> _ratings = new();

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
                Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.",
                AverageRating = 4.5, RatingCount = 12 },
            new() { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Ingredients = "Spaghetti\nGuanciale (or pancetta)\nEggs\nPecorino Romano\nBlack pepper",
                Steps = "1. Cook spaghetti in salted boiling water.\n2. Crisp guanciale in a pan over medium heat.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat; stir in egg mixture quickly.\n6. Serve immediately with extra pecorino.",
                AverageRating = 4.8, RatingCount = 20 },
            new() { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nCanned tomatoes\nHeavy cream\nOnion\nGarlic\nGinger",
                Steps = "1. Marinate chicken in yogurt and spices for 1 hour.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomatoes and simmer 15 minutes.\n5. Stir in cream and cooked chicken.\n6. Simmer 10 minutes and serve with rice.",
                AverageRating = 4.7, RatingCount = 15 },
            new() { Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
                Ingredients = "Rice noodles\nTofu\nBean sprouts\nGreen onions\nPeanuts\nLime\nFish sauce\nTamarind paste\nBrown sugar\nGarlic",
                Steps = "1. Soak rice noodles in warm water 20 minutes.\n2. Press and cube tofu; pan-fry until golden.\n3. Make sauce: tamarind, fish sauce, sugar.\n4. Stir-fry garlic, add noodles and sauce.\n5. Toss with tofu and bean sprouts.\n6. Garnish with peanuts, green onions, lime.",
                AverageRating = 4.3, RatingCount = 8 },
            new() { Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Ingredients = "Ground beef\nTaco shells\nLettuce\nTomato\nCheddar cheese\nSour cream\nTaco seasoning\nOnion",
                Steps = "1. Brown ground beef with diced onion.\n2. Add taco seasoning and water; simmer.\n3. Warm taco shells in the oven.\n4. Dice tomato and shred lettuce.\n5. Fill shells with beef, lettuce, tomato, cheese.\n6. Top with sour cream and serve.",
                AverageRating = 4.1, RatingCount = 10 },
            new() { Id = 6, Title = "Guacamole", Category = "Mexican",
                Ingredients = "Avocados\nLime juice\nCilantro\nRed onion\nJalapeño\nTomato\nSalt\nGarlic",
                Steps = "1. Halve and pit avocados; scoop into bowl.\n2. Mash to desired consistency.\n3. Dice onion, tomato, jalapeño, and cilantro.\n4. Fold vegetables into avocado.\n5. Add lime juice, garlic, and salt.\n6. Serve immediately with tortilla chips.",
                AverageRating = 4.6, RatingCount = 18 },
            new() { Id = 7, Title = "Miso Soup", Category = "Asian",
                Ingredients = "Dashi stock\nMiso paste\nSilken tofu\nWakame seaweed\nGreen onions",
                Steps = "1. Bring dashi stock to a gentle simmer.\n2. Rehydrate wakame in water.\n3. Cube silken tofu.\n4. Dissolve miso paste into the broth (don't boil).\n5. Add tofu and wakame.\n6. Garnish with sliced green onions.",
                AverageRating = 4.2, RatingCount = 6 },
            new() { Id = 8, Title = "Chocolate Lava Cake", Category = "Desserts",
                Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract",
                Steps = "1. Preheat oven to 425°F (220°C).\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until thick.\n4. Fold chocolate mixture into eggs.\n5. Add flour and vanilla; pour into ramekins.\n6. Bake 12-14 minutes; center should be soft.\n7. Invert onto plates and serve immediately.",
                AverageRating = 4.9, RatingCount = 25 },
            new() { Id = 9, Title = "Tiramisu", Category = "Desserts",
                Ingredients = "Ladyfingers\nMascarpone cheese\nEggs\nSugar\nEspresso\nCocoa powder\nMarsala wine",
                Steps = "1. Brew espresso and let it cool; add Marsala.\n2. Separate eggs; beat yolks with sugar.\n3. Fold in mascarpone until smooth.\n4. Whip egg whites to stiff peaks; fold in.\n5. Dip ladyfingers briefly in espresso mixture.\n6. Layer ladyfingers and cream in a dish.\n7. Refrigerate 4+ hours; dust with cocoa.",
                AverageRating = 4.7, RatingCount = 14 },
            new() { Id = 10, Title = "Dal Tadka", Category = "Indian",
                Ingredients = "Yellow lentils (toor dal)\nOnion\nTomato\nGarlic\nCumin seeds\nTurmeric\nRed chili powder\nGhee\nCilantro",
                Steps = "1. Wash and pressure-cook lentils with turmeric.\n2. Heat ghee; add cumin seeds until they splutter.\n3. Sauté onion and garlic until golden.\n4. Add tomatoes and spices; cook until soft.\n5. Pour cooked lentils into the tempering.\n6. Simmer 5 minutes; garnish with cilantro.",
                AverageRating = 4.4, RatingCount = 9 },
        };
    }

    public List<RecipeCategory> GetCategories()
    {
        return _recipes
            .GroupBy(r => r.Category)
            .Select(g => new RecipeCategory
            {
                Name = g.Key,
                Description = g.Key switch
                {
                    "Italian" => "Pasta, pizza, and Mediterranean classics",
                    "Indian" => "Aromatic curries, dals, and spiced dishes",
                    "Asian" => "Flavors from across East and Southeast Asia",
                    "Mexican" => "Bold and vibrant Latin American cuisine",
                    "Desserts" => "Sweet treats and indulgent finishes",
                    _ => ""
                },
                Icon = g.Key switch
                {
                    "Italian" => "🍝",
                    "Indian" => "🍛",
                    "Asian" => "🥢",
                    "Mexican" => "🌮",
                    "Desserts" => "🍰",
                    _ => "🍽️"
                },
                RecipeCount = g.Count()
            })
            .OrderBy(c => c.Name)
            .ToList();
    }

    public List<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes
            .Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round((totalStars + stars) / recipe.RatingCount, 1);
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }
}
"}

