@page "/submit"
@using RecipeShare.Services
@using RecipeShare.Models
@rendermode InteractiveServer

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<h1>📤 Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "<strong>@_model.Title</strong>" has been added.
        <a href="recipe/@_submittedId">View it here</a>.
    </div>
    <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="_model.Title"
                       placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => _model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="_model.Category">
                <option value="">— Select a category —</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Asian">Asian</option>
                <option value="Mexican">Mexican</option>
                <option value="Desserts">Desserts</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="5"
                           @bind-Value="_model.Ingredients"
                           placeholder="One ingredient per line" />
            <ValidationMessage For="() => _model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="6"
                           @bind-Value="_model.Steps"
                           placeholder="Describe each step on its own line" />
            <ValidationMessage For="() => _model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel _model = new();
    private bool _submitted;
    private int _submittedId;

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = _model.Title,
            Category = _model.Category,
            Ingredients = _model.Ingredients,
            Steps = _model.Steps
        };
        RecipeService.AddRecipe(recipe);
        _submittedId = recipe.Id;
        _submitted = true;
    }

    private void Reset()
    {
        _model = new();
        _submitted = false;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title must be under 100 characters.")]
        public string Title { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required.")]
        public string Ingredients { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required.")]
        public string Steps { get; set; } = "";
    }
}

