@using RecipeShare.Services
@using RecipeShare.Models
@using RecipeShare.Components.Shared

<PageTitle>@(_recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (_recipe is not null)
        {
            <li class="breadcrumb-item">
                <a href="recipes/@_recipe.Category.ToLowerInvariant()">@_recipe.Category</a>
            </li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        }
    </ol>
</nav>

@if (_recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <h1>@_recipe.Title</h1>
    <span class="badge bg-info mb-3">@_recipe.Category</span>

    <div class="mb-4">
        <h5>Rate this recipe</h5>
        <StarRating RecipeId="@_recipe.Id"
                    AverageRating="@_recipe.AverageRating"
                    RatingCount="@_recipe.RatingCount"
                    OnRated="HandleRating" />
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-header"><strong>🥘 Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in _recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <div class="card">
                <div class="card-header"><strong>📝 Steps</strong></div>
                <div class="card-body">
                    @foreach (var step in _recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private Recipe? _recipe;

    protected override void OnInitialized()
    {
        _recipe = RecipeService.GetRecipeById(Id);
    }

    private void HandleRating(int stars)
    {
        RecipeService.AddRating(Id, stars);
        _recipe = RecipeService.GetRecipeById(Id);
    }
}
